console.log("正在编辑博客类型，blogTypeId = "+linkTypeId);layui.use(["form","layer"],function(){let form=layui.form;let layer=layui.layer;let linkType;if(linkTypeId){$.ajax({url:"/link_type/"+linkTypeId,method:"GET",dataType:"json",success:function(a){if(a.request==="success"&&a.status===200&&a.data){linkType=a.data[0];form.val("form-linkType",{id:linkType.id,name:linkType.name});form.render()}else{layer.msg(a.message+", 错误码: "+a.status,{icon:2})}},error:function(a){if(a){layer.msg(a)}else{layer.msg("请求错误，请检查网络",{icon:2})}}});form.on("submit(form-linkType-submit)",function(a){let linkType=a.field;layer.confirm("确认提交？",{btn:["确认","取消"]},function(b){$.ajax({url:"/link_type/"+linkTypeId,data:{name:linkType.name},method:"PUT",dateType:"json",success:function(c){if(c.request==="success"&&c.status===200){layer.msg(c.message,{icon:1})}else{layer.msg(c.message+", 错误码: "+c.status,{icon:2})}},error:function(c){if(c){layer.msg(c)}else{layer.msg("请求错误，请检查网络",{icon:2})}}});layer.close(b)});return false});form.verify({name:function(b,a){let nameRex=/^[\w\W\s\u4e00-\u9fcc]{2,20}$/;if(!nameRex.test(b)){return"链接类型名只能为2-20个字符"}}})}else{layer.msg("参数错误",{icon:2})}});